    cur = a[0];
    out[0] = cur;
    /*@ Inv exists l1,
          1 <= i && i <= n@pre &&
          a == a@pre &&
          n == n@pre &&
          n + 1 <= INT_MAX &&
          out == out@pre &&
          n@pre == Zlength(la) &&
          n@pre == Zlength(lo) &&
          Zlength(l1) == i &&
          cur == max_list_nonempty(sublist(0, i, la)) &&
          (forall (k: Z),
            (0 <= k && k < i) =>
            l1[k] == max_list_nonempty(sublist(0, k + 1, la))) &&
          IntArray::full(a, n@pre, la) *
          IntArray::full(out, n@pre, app(l1, sublist(i, n@pre, lo)))
    */
    for (i = 1; i < n; ++i) {
        if (a[i] > cur) {
            cur = a[i];
        }
        /*@ Assert exists l1,
